// MARK: - URLSessionDelegate (SSL/TLS Handling)

extension NetworkManager: URLSessionDelegate, URLSessionTaskDelegate {
    
    /// Handle authentication challenges for both secure and insecure connections
    func urlSession(
        _ session: URLSession,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        let host = challenge.protectionSpace.host
        
        // For local network devices, accept self-signed certificates if they use HTTPS
        if host.hasPrefix(localNetworkPrefix) || host == "localhost" || host == "127.0.0.1" {
            if challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust,
               let serverTrust = challenge.protectionSpace.serverTrust {
                let credential = URLCredential(trust: serverTrust)
                completionHandler(.useCredential, credential)
                print("[NetworkManager] Accepted self-signed certificate for local device: \(host)")
                return
            }
        }
        
        // For cloud connections, use default handling (proper certificate validation)
        completionHandler(.performDefaultHandling, nil)
    }
    
    func urlSession(
        _ session: URLSession,
        task: URLSessionTask,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        let host = challenge.protectionSpace.host
        
        if host.hasPrefix(localNetworkPrefix) || host == "localhost" || host == "127.0.0.1" {
            if challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust,
               let serverTrust = challenge.protectionSpace.serverTrust {
                let credential = URLCredential(trust: serverTrust)
                completionHandler(.useCredential, credential)
                return
            }
        }
        
        completionHandler(.performDefaultHandling, nil)
    }
}

// MARK: - Cloud API Service

class CloudAPIService {
    
    private let network = NetworkManager.shared
    private var authToken: String?
    
    private var authHeaders: [String: String] {
        var headers: [String: String] = [:]
        if let token = authToken {
            headers["Authorization"] = "Bearer \(token)"
        }
        return headers
    }
    
    func setAuthToken(_ token: String) {
        self.authToken = token
    }
    
    // MARK: - Auth
    
    struct LoginRequest: Encodable {
        let email: String
        let password: String
    }
    
    struct LoginResponse: Decodable {
        let token: String
        let userId: String
        let expiresAt: Date
    }
    
    func login(email: String, password: String) async throws -> LoginResponse {
        let response = try await network.request(
            target: .cloud,
            path: "/v1/auth/login",
            method: .POST,
            body: LoginRequest(email: email, password: password),
            responseType: LoginResponse.self
        )
        self.authToken = response.token
        return response
    }
    
    // MARK: - Devices
    
    struct DeviceRegistration: Codable {
        let deviceId: String
        let name: String
        let type: String
        let firmwareVersion: String
        let localIp: String?
        let localPort: Int?
    }
    
    struct DeviceListResponse: Decodable {
        let devices: [DeviceRegistration]
        let totalCount: Int
    }
    
    func getRegisteredDevices() async throws -> DeviceListResponse {
        return try await network.request(
            target: .cloud,
            path: "/v1/devices",
            method: .GET,
            headers: authHeaders,
            responseType: DeviceListResponse.self
        )
    }
    
    func registerDevice(_ device: DeviceRegistration) async throws -> DeviceRegistration {
        return try await network.request(
            target: .cloud,
            path: "/v1/devices",
            method: .POST,
            headers: authHeaders,
            body: device,
            responseType: DeviceRegistration.self
        )
    }
    
    // MARK: - Telemetry
    
    struct TelemetryData: Decodable {
        let deviceId: String
        let timestamp: Date
        let readings: [String: Double]
    }
    
    func getDeviceTelemetry(deviceId: String, from: Date? = nil, to: Date? = nil) async throws -> [TelemetryData] {
        var queryItems: [URLQueryItem] = []
        let formatter = ISO8601DateFormatter()
        
        if let from = from {
            queryItems.append(URLQueryItem(name: "from", value: formatter.string(from: from)))
        }
        if let to = to {
            queryItems.append(URLQueryItem(name: "to", value: formatter.string(from: to)))
        }
        
        return try await network.request(
            target: .cloud,
            path: "/v1/devices/\(deviceId)/telemetry",
            method: .GET,
            queryItems: queryItems.isEmpty ? nil : queryItems,
            headers: authHeaders,
            responseType: [TelemetryData].self
        )
    }
}

// MARK: - Local IoT Device Service

class LocalDeviceService {
    
    private let network = NetworkManager.shared
    
    // MARK: - Device Models
    
    struct DeviceInfo: Decodable {
        let id: String
        let name: String
        let type: String
        let firmwareVersion: String
        let uptime: Int
        let status: String
    }
    
    struct DeviceStatus: Decodable {
        let online: Bool
        let temperature: Double?
        let humidity: Double?
        let batteryLevel: Double?
        let wifiSignalStrength: Int?
        let lastUpdated: String
    }
    
    struct DeviceCommand: Encodable {
        let command: String
        let parameters: [String: String]?
    }
    
    struct CommandResponse: Decodable {
        let success: Bool
        let message: String?
        let data: [String: String]?
    }
    
    struct DeviceConfiguration: Codable {
        let ssid: String?
        let reportingInterval: Int?
        let thresholds: [String: Double]?
        let enableNotifications: Bool?
    }
    
    // MARK: - Discovery
    
    /// Scan local network for IoT devices by attempting to connect to common ports
    func discoverDevices(
        subnet: String = "192.168.1",
        port: Int = 80,
        startHost: Int = 1,
        endHost: Int = 254
    ) async -> [String: DeviceInfo] {
        var discoveredDevices: [String: DeviceInfo] = [:]
        let lock = NSLock()
        
        await withTaskGroup(of: (String, DeviceInfo?).self) { group in
            for host in startHost...endHost {
                let ip = "\(subnet).\(host)"
                group.addTask {
                    do {
                        let info = try await self.getDeviceInfo(ip: ip, port: port)
                        return (ip, info)
                    } catch {
                        return (ip, nil)
                    }
                }
            }
            
            for await (ip, info) in group {
                if let info = info {
                    lock.lock()
                    discoveredDevices[ip] = info
                    lock.unlock()
                    print("[Discovery] Found device at \(ip): \(info.name) (\(info.type))")
                }
            }
        }
        
        return discoveredDevices
    }
    
    // MARK: - Device Communication
    
    /// Get device information
    func getDeviceInfo(ip: String, port: Int? = nil) async throws -> DeviceInfo {
        return try await network.request(
            target: .localDevice(ip: ip, port: port),
            path: "/api/info",
            method: .GET,
            responseType: DeviceInfo.self
        )
    }
    
    /// Get device status and sensor readings
    func getDeviceStatus(ip: String, port: Int? = nil) async throws -> DeviceStatus {
        return try await network.request(
            target: .localDevice(ip: ip, port: port),
            path: "/api/status",
            method: .GET,
            responseType: DeviceStatus.self
        )
    }
    
    /// Send a command to a device
    func sendCommand(ip: String, port: Int? = nil, command: String, parameters: [String: String]? = nil) async throws -> CommandResponse {
        let cmd = DeviceCommand(command: command, parameters: parameters)
        return try await network.request(
            target: .localDevice(ip: ip, port: port),
            path: "/api/command",
            method: .POST,
            body: cmd,
            responseType: CommandResponse.self
        )
    }
    
    /// Update device configuration
    func updateConfiguration(ip: String, port: Int? = nil, config: DeviceConfiguration) async throws -> CommandResponse {
        return try await network.request(
            target: .localDevice(ip: ip, port: port),
            path: "/api/config",
            method: .PUT,
            body: config,
            responseType: CommandResponse.self
        )
    }
    
    /// Get device configuration
    func getConfiguration(ip: String, port: Int? = nil) async throws -> DeviceConfiguration {
        return try await network.request(
            target: .localDevice(ip: ip, port: port),
            path: "/api/config",
            method: .GET,
            responseType: DeviceConfiguration.self
        )
    }
    
    /// Trigger firmware update on device
    func triggerFirmwareUpdate(ip: String, port: Int? = nil, firmwareURL: String) async throws -> CommandResponse {
        return try await sendCommand(
            ip: ip,
            port: port,
            command: "firmware_update",
            parameters: ["url": firmwareURL]
        )
    }
    
    /// Reboot device
    func rebootDevice(ip: String, port: Int? = nil) async throws -> CommandResponse {
        return try await sendCommand(ip: ip, port: port, command: "reboot")
    }
    
    /// Factory reset device
    func factoryReset(ip: String, port: Int? = nil) async throws -> CommandResponse {
        return try await sendCommand(ip: ip, port: port, command: "factory_reset")
    }
}

// MARK: - Unified Device Manager

class DeviceManager {
    
    let cloudService = CloudAPIService()
    let localService = LocalDeviceService()
    
    struct ManagedDevice {
        let registration: CloudAPIService.DeviceRegistration
        var localInfo: LocalDeviceService.DeviceInfo?
        var localStatus: LocalDeviceService.DeviceStatus?
        var isLocallyReachable: Bool = false
    }
    
    private var managedDevices: [String: ManagedDevice] = [:]
    
    /// Sync cloud-registered devices with local network discovery
    func syncDevices() async throws -> [ManagedDevice] {
        // Fetch registered devices from cloud
        let cloudResponse = try await cloudService.getRegisteredDevices()
        
        // Discover local devices
        let localDevices = await localService.discoverDevices()
        
        // Merge cloud and local data
        var synced: [ManagedDevice] = []
        
        for registration in cloudResponse.devices {
            var managed = ManagedDevice(registration: registration)
            
            // Check if the device is reachable locally
            if let localIp = registration.localIp {
                if let localInfo = localDevices[localIp] {
                    managed.localInfo = localInfo
                    managed.isLocallyReachable = true
                    
                    // Fetch status from local device
                    if let status = try? await localService.getDeviceStatus(
                        ip: localIp,
                        port: registration.localPort
                    ) {
                        managed.localStatus = status
                    }
                }
            }
            
            managedDevices[registration.deviceId] = managed
            synced.append(managed)
        }
        
        return synced
    }
    
    /// Send command to device, preferring local connection
    func sendCommand(
        deviceId: String,
        command: String,
        parameters: [String: String]? = nil
    ) async throws -> LocalDeviceService.CommandResponse {
        guard let device = managedDevices[deviceId] else {
            throw NetworkManager.NetworkError.invalidURL
        }
        
        // Prefer local connection for lower latency
        if device.isLocallyReachable, let ip = device.registration.localIp {
            return try await localService.sendCommand(
                ip: ip,
                port: device.registration.localPort,
                command: command,
                parameters: parameters
            )
        }
        
        // Fallback: could implement cloud relay here
        throw NetworkManager.NetworkError.deviceUnreachable(device.registration.localIp ?? "unknown")
    }
}

