 </array>
*/

// MARK: - Usage Example

func exampleUsage() async {
    let manager = DeviceManager()
    
    // 1. Login to cloud
    do {
        let loginResponse = try await manager.cloudService.login(
            email: "user@example.com",
            password: "securePassword123"
        )
        print("Logged in. Token expires at: \(loginResponse.expiresAt)")
    } catch {
        print("Login failed: \(error.localizedDescription)")
        return
    }
    
    // 2. Sync devices (cloud + local discovery)
    do {
        let devices = try await manager.syncDevices()
        print("Found \(devices.count) managed devices")
        
        for device in devices {
            print("  - \(device.registration.name): local=\(device.isLocallyReachable)")
            if let status = device.localStatus {
                print("    Temperature: \(status.temperature ?? 0)°C")
                print("    Humidity: \(status.humidity ?? 0)%")
            }
        }
    } catch {
        print("Sync failed: \(error.localizedDescription)")
    }
    
    // 3. Direct local device communication
    let localService = manager.localService
    
    do {
        let info = try await localService.getDeviceInfo(ip: "192.168.1.100", port: 8080)
        print("Device: \(info.name), Firmware: \(info.firmwareVersion)")
        
        let status = try await localService.getDeviceStatus(ip: "192.168.1.100", port: 8080)
        print("Online: \(status.online), Temp: \(status.temperature ?? 0)")
        
        // Send a command
        let response = try await localService.sendCommand(
            ip: "192.168.1.100",
            port: 8080,
            command: "set_led",
            parameters: ["color": "blue", "brightness": "80"]
        )
        print("Command result: \(response.success) - \(response.message ?? "")")
        
        // Update configuration
        let config = LocalDeviceService.DeviceConfiguration(
            ssid: nil,
            reportingInterval: 30,
            thresholds: ["temperature": 35.0, "humidity": 80.0],
            enableNotifications: true
        )
        let configResponse = try await localService.updateConfiguration(
            ip: "192.168.1.100",
            port: 8080,
            config: config
        )
        print("Config updated: \(configResponse.success)")
        
    } catch {
        print("Local device error: \(error.localizedDescription)")
    }
    
    // 4. Cloud telemetry
    do {
        let telemetry = try await manager.cloudService.getDeviceTelemetry(
            deviceId: "device-001",
            from: Calendar.current.date(byAdding: .hour, value: -24, to: Date())
        )
        print("Received \(telemetry.count) telemetry records")
    } catch {
        print("Telemetry error: \(error.localizedDescription)")
    }
    
    // 5. Discover all devices on network
    let discovered = await localService.discoverDevices(
        subnet: "192.168.1",
        port: 80,
        startHost: 1,
        endHost: 254
    )
    print("Discovered \(discovered.count) devices on local network")
    for (ip, info) in discovered {
        print("  \(ip): \(info.name) (\(info.type)) - FW \(info.firmwareVersion)")
    }
}